import React from 'react'

import SunCalc from 'suncalc'

const AzimuthChart = (props) => {
  // const azimuth = []
  // const sunrise = SunCalc.getTimes(props.date, props.latitude, props.longitude)
  // const sunriseAzi = SunCalc.getPosition(props.sunrise, props.latitude, props.longitude)
  // sunrise = SunCalc.getTimes()
  // console.log(sunriseAzi)
  function polarToCartesian(centerX, centerY, radius, angleInDegrees) {
    var angleInRadians = (angleInDegrees-90) * Math.PI / 180.0;

    return {
      x: centerX + (radius * Math.cos(angleInRadians)),
      y: centerY + (radius * Math.sin(angleInRadians))
    };
  }

  function describeArc(x, y, radius, startAngle, endAngle){

      var start = polarToCartesian(x, y, radius, endAngle);
      var end = polarToCartesian(x, y, radius, startAngle);

      var largeArcFlag = endAngle - startAngle <= 180 ? "0" : "1";

      var d = [
          "M", start.x, start.y, 
          "A", radius, radius, 0, largeArcFlag, 0, end.x, end.y
      ].join(" ");

      return d;       
  }

  window.onload = function() {
    document.getElementById("arc1").setAttribute("d", describeArc(150, 150, 100, 0, 270));
  };

  return (
    <div className="App">
      <svg preserveAspectRatio="xMidYMin" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 800 400">
        <g fill="#61DAFB">
          <circle cx="400" cy="200" r="100"/>
          <circle cx='400' cy='200' r='50' fill='bisque'
            stroke='tomato'
            stroke-width='100'
            strokeDasharray='10^100'
          />
        </g>
      </svg>
    </div>
  )
} 

export default AzimuthChart
